using System;

class Program
{
    static int GCD(int a, int b)
    {
        while (b != 0)
        {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    static int LCM(int a, int b)
    {
        return (a * b) / GCD(a, b);
    }

    static void Main()
    {
        int num1 = 48;
        int num2 = 18;

        int gcd = GCD(num1, num2);
        int lcm = LCM(num1, num2);

        Console.WriteLine($"Sayilar: {num1} ve {num2}");
        Console.WriteLine($"EBOB (GCD): {gcd}");
        Console.WriteLine($"EKOK (LCM): {lcm}");

        // Birden fazla çift için tablo
        Console.WriteLine("\nFarkli sayi ciftleri:");
        int[,] pairs = { { 12, 18 }, { 7, 13 }, { 100, 75 }, { 24, 36 } };

        for (int i = 0; i < pairs.GetLength(0); i++)
        {
            int a = pairs[i, 0];
            int b = pairs[i, 1];
            Console.WriteLine($"GCD({a},{b}) = {GCD(a, b)}, LCM({a},{b}) = {LCM(a, b)}");
        }
    }
}
